import{c as a,Q as n,j as e,m as t}from"./chunks/framework.CBiVa4O3.js";const k=JSON.parse('{"title":"容器与云安全:K8s 攻击面 / IAM 错配 / Secret 管理","description":"","frontmatter":{},"headers":[],"relativePath":"../securityLearning/28-容器与云安全.md","filePath":"../securityLearning/28-容器与云安全.md","lastUpdated":1778496697000}'),i={name:"../securityLearning/28-容器与云安全.md"};function p(l,s,o,c,r,d){return n(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="容器与云安全-k8s-攻击面-iam-错配-secret-管理" tabindex="-1">容器与云安全:K8s 攻击面 / IAM 错配 / Secret 管理 <a class="header-anchor" href="#容器与云安全-k8s-攻击面-iam-错配-secret-管理" aria-label="Permalink to &quot;容器与云安全:K8s 攻击面 / IAM 错配 / Secret 管理&quot;">​</a></h1><p>容器和 K8s 在过去十年把部署体验抬到了一个新的高度,<strong>但同时也把&quot;安全边界&quot;从机器边界,变成了配置文件里的几行 YAML</strong>——一行 <code>privileged: true</code> 写错,或者一个 IAM Role 多挂了一条 <code>*:*</code>,就足够让攻击者从一个 Pod 走到整个集群,再走到整个云账号。这一篇不重复 osLearning/25 的容器底层(namespace / cgroup / overlayfs)、也不重复 backendLearning/27-30 的 K8s 部署套路——<strong>这里只讲&quot;攻击者怎么打容器化系统、防御方应该把哪些 checklist 写进上线流程&quot;</strong>。</p><blockquote><p>一句话先记住:<strong>容器不是虚拟机,共享宿主机内核——逃逸路径不是&quot;难不难&quot;而是&quot;配错没&quot;</strong>;K8s 的 API Server 是整个集群的&quot;宙斯之眼&quot;,拿到一个有权限的 ServiceAccount Token 等价于拿到对应资源的 root;<strong>云上 90% 的真实事故不是 0day,是 IAM 错配 + Secret 泄露</strong>——Capital One、Tesla、Codecov 三个标杆事故串起来就是一句话:<strong>配错比写错更危险</strong>。</p></blockquote><hr><h2 id="一、容器逃逸的本质-你和宿主机共享内核" tabindex="-1">一、容器逃逸的本质:你和宿主机共享内核 <a class="header-anchor" href="#一、容器逃逸的本质-你和宿主机共享内核" aria-label="Permalink to &quot;一、容器逃逸的本质:你和宿主机共享内核&quot;">​</a></h2><h3 id="_1-1-一个反直觉的事实" tabindex="-1">1.1 一个反直觉的事实 <a class="header-anchor" href="#_1-1-一个反直觉的事实" aria-label="Permalink to &quot;1.1 一个反直觉的事实&quot;">​</a></h3><p>很多工程师第一次接触容器时,默认它和虚拟机差不多——&quot;容器是个小盒子,逃出来很难&quot;。<strong>这个心智模型是错的</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>虚拟机                          容器</span></span>
<span class="line"><span>┌─────────┐ ┌─────────┐         ┌────┐ ┌────┐ ┌────┐</span></span>
<span class="line"><span>│ Guest OS│ │ Guest OS│         │App │ │App │ │App │</span></span>
<span class="line"><span>│  内核 1  │ │  内核 2  │         │ns/cg│ │ns/cg│ │ns/cg│</span></span>
<span class="line"><span>├─────────┴─┴─────────┤         ├────┴─┴────┴─┴────┤</span></span>
<span class="line"><span>│   Hypervisor (-1)   │         │   Host 内核 (唯一) │  ← 共享!</span></span>
<span class="line"><span>├─────────────────────┤         ├──────────────────┤</span></span>
<span class="line"><span>│     Host 硬件        │         │     Host 硬件     │</span></span>
<span class="line"><span>└─────────────────────┘         └──────────────────┘</span></span>
<span class="line"><span>  每 VM 一个内核                   所有容器共享一个内核</span></span></code></pre></div><p><strong>关键差别</strong>:VM 逃逸要打穿 Hypervisor(硬件辅助级别漏洞,极少且昂贵);<strong>容器&quot;逃逸&quot;本质上是&quot;在共享内核上拿到宿主特权&quot;</strong>——只要内核有一个能提权的漏洞,或者你&quot;配错了&quot;把宿主资源直接给了容器,逃逸就是几行命令的事。</p><h3 id="_1-2-容器安全的三个根因" tabindex="-1">1.2 容器安全的三个根因 <a class="header-anchor" href="#_1-2-容器安全的三个根因" aria-label="Permalink to &quot;1.2 容器安全的三个根因&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 共享内核</span></span>
<span class="line"><span>   → 任何能 root 提权的内核漏洞 = 全部容器一起逃</span></span>
<span class="line"><span>   (Dirty COW / DirtyPipe / OverlayFS bug)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 配置即权限</span></span>
<span class="line"><span>   → privileged / capabilities / hostPath / hostNetwork</span></span>
<span class="line"><span>     这些 YAML 字段每一项都能直接打通容器墙</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 信任链的远端是宿主机</span></span>
<span class="line"><span>   → docker.sock / kubelet socket / 容器运行时</span></span>
<span class="line"><span>     拿到这些 = 拿到能创建新容器的权力 = root</span></span></code></pre></div><blockquote><p>一句话:<strong>容器的安全姿势更像&quot;加了几道纸糊门的进程&quot;,不是&quot;加了一堵钢墙的虚拟机&quot;</strong>。</p></blockquote><hr><h2 id="二、docker-逃逸的四条路径" tabindex="-1">二、Docker 逃逸的四条路径 <a class="header-anchor" href="#二、docker-逃逸的四条路径" aria-label="Permalink to &quot;二、Docker 逃逸的四条路径&quot;">​</a></h2><h3 id="_2-1-路径-a-privileged-容器" tabindex="-1">2.1 路径 A:<code>--privileged</code> 容器 <a class="header-anchor" href="#_2-1-路径-a-privileged-容器" aria-label="Permalink to &quot;2.1 路径 A:\`--privileged\` 容器&quot;">​</a></h3><p><code>docker run --privileged</code> 这个参数曾经是&quot;什么都跑得起来&quot;的万能钥匙——它做了什么?</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>--privileged 实际做了:</span></span>
<span class="line"><span>  - 给容器所有 capabilities(CAP_SYS_ADMIN 等 30+)</span></span>
<span class="line"><span>  - 不再 apply seccomp / AppArmor profile</span></span>
<span class="line"><span>  - 把 /dev 全部挂进来</span></span>
<span class="line"><span>  - 不再 mask /proc 中的敏感路径</span></span></code></pre></div><p><strong>有了这套权限,逃逸基本就是&quot;挂宿主磁盘&quot;</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 在 privileged 容器内</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 1. 看到宿主机所有块设备</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fdisk</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 2. 直接挂载宿主根分区</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /host</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mount</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/sda1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /host</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 3. 现在 /host 就是宿主的 /</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chroot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /host</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 4. 你已经在宿主机上是 root 了</span></span></code></pre></div><p>这不是漏洞,这是设计——<code>--privileged</code> 的语义就是&quot;我信任这个容器,等同 root&quot;。但<strong>绝大多数业务容器根本不需要它</strong>——监控、网络抓包等少数场景要,通常也有更窄的替代方案(<code>--cap-add=NET_ADMIN</code>)。</p><h3 id="_2-2-路径-b-挂载-docker-sock" tabindex="-1">2.2 路径 B:挂载 <code>docker.sock</code> <a class="header-anchor" href="#_2-2-路径-b-挂载-docker-sock" aria-label="Permalink to &quot;2.2 路径 B:挂载 \`docker.sock\`&quot;">​</a></h3><p>CI / CD 工具(Jenkins agent、GitLab Runner)经常把宿主的 <code>/var/run/docker.sock</code> 挂进容器,&quot;这样容器里就能跑 docker 命令&quot;。<strong>但这个 socket 等价于宿主的 root</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 容器内挂了 docker.sock</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /:/host</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> alpine</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> chroot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /host</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 直接拉了一个新容器,把宿主 / 挂进去 → 拿到宿主 root</span></span></code></pre></div><p>DinD(Docker-in-Docker)看起来&quot;在容器里跑 docker&quot;,<strong>实际上是在和宿主的 Docker daemon 说话</strong>——你的&quot;嵌套容器&quot;和外层容器是兄弟,不是父子。</p><h3 id="_2-3-路径-c-危险的-capabilities" tabindex="-1">2.3 路径 C:危险的 capabilities <a class="header-anchor" href="#_2-3-路径-c-危险的-capabilities" aria-label="Permalink to &quot;2.3 路径 C:危险的 capabilities&quot;">​</a></h3><p>Linux capabilities 把传统的 &quot;root / non-root 二元权限&quot; 拆成了 40 多个细粒度权限。容器默认裁掉了大部分,但<strong>有几个一旦给了就等于逃逸</strong>:</p><table tabindex="0"><thead><tr><th>capability</th><th>给了之后能干啥</th></tr></thead><tbody><tr><td><code>CAP_SYS_ADMIN</code></td><td>几乎等于 root(挂载、改 namespace、改 cgroup)</td></tr><tr><td><code>CAP_SYS_PTRACE</code></td><td>ptrace 宿主进程,读它的内存</td></tr><tr><td><code>CAP_SYS_MODULE</code></td><td>加载内核模块 → 自己写一个内核 rootkit</td></tr><tr><td><code>CAP_NET_ADMIN</code></td><td>改路由、抓包、ARP 欺骗</td></tr><tr><td><code>CAP_DAC_READ_SEARCH</code></td><td>绕过文件权限读宿主任意文件</td></tr></tbody></table><p><strong><code>CAP_SYS_ADMIN</code> 是 &quot;新 root&quot;</strong>——Docker 默认不给,但很多人为了 &quot;解决某个权限报错&quot; 就加上,等于放弃了大部分容器隔离。</p><h3 id="_2-4-路径-d-内核漏洞" tabindex="-1">2.4 路径 D:内核漏洞 <a class="header-anchor" href="#_2-4-路径-d-内核漏洞" aria-label="Permalink to &quot;2.4 路径 D:内核漏洞&quot;">​</a></h3><p>共享内核意味着<strong>任何内核 root LPE 都是潜在的逃逸路径</strong>:<strong>Dirty COW</strong> (CVE-2016-5195,COW race,可写任意只读文件)、<strong>DirtyPipe</strong> (CVE-2022-0847,pipe buffer 标志位 bug)、<strong>runC CVE-2019-5736</strong>(容器覆盖宿主 runc 二进制,下次 exec 就是攻击者代码)、<strong>CVE-2022-0185</strong>(fsconfig 整数溢出,user namespace 内触发)、<strong>OverlayFS CVE-2023-0386</strong>。<strong>防御</strong>:及时打 kernel 补丁、最小镜像、开 seccomp 默认 profile(屏蔽 200+ 罕用 syscall)、不要无脑开 user namespace。</p><h3 id="_2-5-一张逃逸优先级图" tabindex="-1">2.5 一张逃逸优先级图 <a class="header-anchor" href="#_2-5-一张逃逸优先级图" aria-label="Permalink to &quot;2.5 一张逃逸优先级图&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>攻击者拿到容器内 RCE</span></span>
<span class="line"><span>   │</span></span>
<span class="line"><span>   ├── 看 /proc/self/status 的 CapEff</span></span>
<span class="line"><span>   │     有 CAP_SYS_ADMIN? → 直接挂宿主磁盘</span></span>
<span class="line"><span>   │</span></span>
<span class="line"><span>   ├── 看 mount 输出</span></span>
<span class="line"><span>   │     有 docker.sock? → docker run -v / chroot</span></span>
<span class="line"><span>   │     有 /host or hostPath? → 直接 chroot</span></span>
<span class="line"><span>   │</span></span>
<span class="line"><span>   ├── 看 /proc/1/cgroup</span></span>
<span class="line"><span>   │     是 privileged? → 内核模块 / 直接 mount</span></span>
<span class="line"><span>   │</span></span>
<span class="line"><span>   └── 都没有 → 找内核 LPE</span></span>
<span class="line"><span>         (DirtyPipe / overlayfs / nf_tables)</span></span></code></pre></div><hr><h2 id="三、镜像层的风险-你-pull-进来的东西" tabindex="-1">三、镜像层的风险:你 pull 进来的东西 <a class="header-anchor" href="#三、镜像层的风险-你-pull-进来的东西" aria-label="Permalink to &quot;三、镜像层的风险:你 pull 进来的东西&quot;">​</a></h2><p>容器逃逸是&quot;运行时&quot;的事,<strong>而镜像层的漏洞在你 <code>docker build</code> 那一刻就已经埋下了</strong>。</p><h3 id="_3-1-base-image-投毒" tabindex="-1">3.1 base image 投毒 <a class="header-anchor" href="#_3-1-base-image-投毒" aria-label="Permalink to &quot;3.1 base image 投毒&quot;">​</a></h3><div class="language-dockerfile vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">dockerfile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 看起来人畜无害</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> node:18</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 实际拉下来的可能是:</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#  - 官方 node:18(好)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#  - 攻击者发布的 nodee:18(typosquatting,坏)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#  - 第三方 registry 的 node:18(中间人改过的)</span></span></code></pre></div><p>历史上 Docker Hub 多次出现&quot;看起来像官方&quot;的恶意镜像——里面预埋挖矿程序、反弹 shell、或者后门到 npm 全局包。<strong>对策</strong>:</p><ul><li>用 <strong>digest 锁定</strong>:<code>FROM node:18@sha256:abc...</code> 而不是 tag</li><li>用可信 registry(GCR / ECR / Harbor)+ 私有镜像缓存</li><li>用 Cosign / Notary 验证镜像签名(见 26 篇供应链)</li></ul><h3 id="_3-2-latest-tag-的诅咒" tabindex="-1">3.2 <code>latest</code> tag 的诅咒 <a class="header-anchor" href="#_3-2-latest-tag-的诅咒" aria-label="Permalink to &quot;3.2 \`latest\` tag 的诅咒&quot;">​</a></h3><div class="language-dockerfile vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">dockerfile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> nginx:latest</span></span></code></pre></div><p><code>latest</code> 不是&quot;最新稳定版&quot;,是&quot;上次推 latest 的人推的版本&quot;。结果:</p><ul><li>不同时间 build 出来的镜像内容<strong>完全不同</strong></li><li>攻击者推了恶意 latest,你下次 build 就中招</li><li>出了 bug 没法 rollback 到&quot;上次工作的版本&quot;</li></ul><p><strong>生产镜像必须 pin 到具体 tag 或 digest</strong>——这是基本卫生。</p><h3 id="_3-3-默认-root-用户" tabindex="-1">3.3 默认 root 用户 <a class="header-anchor" href="#_3-3-默认-root-用户" aria-label="Permalink to &quot;3.3 默认 root 用户&quot;">​</a></h3><p>绝大多数 base image 默认以 <code>USER root</code> 启动。<strong>容器内的 root,在没开 user namespace 时,UID 0 = 宿主的 UID 0</strong>——一旦逃逸,直接是宿主 root。</p><div class="language-dockerfile vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">dockerfile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 修复</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">RUN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> groupadd -r app &amp;&amp; useradd -r -g app app</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">USER</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> app</span></span></code></pre></div><p>或者在 K8s 的 <code>securityContext</code> 里强制 <code>runAsNonRoot: true</code>,直接拒绝 root 启动。</p><h3 id="_3-4-镜像里的-老朋友" tabindex="-1">3.4 镜像里的&quot;老朋友&quot; <a class="header-anchor" href="#_3-4-镜像里的-老朋友" aria-label="Permalink to &quot;3.4 镜像里的&quot;老朋友&quot;&quot;">​</a></h3><p>镜像层的扫描结果往往让人惊讶:一个 Alpine base 也能扫出几十个 CVE,Ubuntu base 一两百个。<strong>关键不是&quot;有多少 CVE&quot;,是&quot;有没有可达路径&quot;</strong>:</p><ul><li>镜像里有 <code>curl</code>、<code>bash</code>、<code>apt-get</code>?→ 攻击者拿到 RCE 后下载工具更方便</li><li>镜像里有编译器(<code>gcc</code>)?→ 可以现场编 exploit</li><li>镜像里有 <code>setuid</code> 二进制?→ 提权路径</li></ul><p><strong>最佳实践</strong>:<strong>distroless / scratch / alpine-no-shell</strong>——只放二进制和必要的运行时库,不放 shell、不放包管理器。攻击者就算 RCE 了也举步维艰。</p><hr><h2 id="四、k8s-的攻击面-从一个-pod-走到全集群" tabindex="-1">四、K8s 的攻击面:从一个 Pod 走到全集群 <a class="header-anchor" href="#四、k8s-的攻击面-从一个-pod-走到全集群" aria-label="Permalink to &quot;四、K8s 的攻击面:从一个 Pod 走到全集群&quot;">​</a></h2><p>容器逃逸只是&quot;拿到一个节点&quot;,<strong>K8s 的真正问题是&quot;拿到一个节点之后呢&quot;</strong>——攻击者期望的路径是:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>应用漏洞 (RCE)</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>拿到 Pod 内 shell</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>读 ServiceAccount Token (挂在 /var/run/secrets/kubernetes.io/serviceaccount/)</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>用 Token 调 API Server</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>RBAC 过宽? → list/get secrets / exec into kube-system pods</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>拿到 kube-system 的 token / cloud credentials</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>整个集群陷落</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>拿到 Node 上的 kubelet credentials / 云 IAM 角色</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>整个云账号陷落</span></span></code></pre></div><p><strong>这条路径上每一跳都对应一类错配</strong>。</p><h3 id="_4-1-暴露的-api-server-kubelet" tabindex="-1">4.1 暴露的 API Server / kubelet <a class="header-anchor" href="#_4-1-暴露的-api-server-kubelet" aria-label="Permalink to &quot;4.1 暴露的 API Server / kubelet&quot;">​</a></h3><p><code>kube-apiserver</code> 默认监听 6443,<strong>应该只对内网或 VPN 暴露</strong>。但历史上无数集群直接挂公网,加上 <code>--anonymous-auth=true</code>、错配的 <code>system:anonymous</code> 绑到 <code>cluster-admin</code>、<code>/debug/pprof</code> 泄露内存——一条龙翻车。</p><p><code>kubelet</code> 是另一个常被忽视的入口——默认监听 10250,提供 <code>exec</code> / <code>logs</code> / <code>run</code> 端点。<strong>配成允许匿名 + 给了权限</strong>,任何人都能等价 <code>kubectl exec</code>。Shodan 上常年能搜到几千个开放的 kubelet:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>curl -k https://NODE:10250/pods                     ← 列出所有 Pod</span></span>
<span class="line"><span>curl -k -XPOST https://NODE:10250/run/NS/POD/CTN \\</span></span>
<span class="line"><span>     -d &quot;cmd=cat /etc/shadow&quot;                       ← 任意命令</span></span></code></pre></div><p><strong>防御</strong>:<code>--anonymous-auth=false</code>、<code>--authorization-mode=Webhook</code>、kubelet 只监听 node 本地 / 私网、API Server 前置 IAM 网关(GKE master authorized networks / AKS private cluster)。</p><h3 id="_4-2-rbac-过宽-默认-cluster-admin" tabindex="-1">4.2 RBAC 过宽 = &quot;默认 cluster-admin&quot; <a class="header-anchor" href="#_4-2-rbac-过宽-默认-cluster-admin" aria-label="Permalink to &quot;4.2 RBAC 过宽 = &quot;默认 cluster-admin&quot;&quot;">​</a></h3><p>K8s RBAC 设计上是白名单,但<strong>实际部署里常见的几个反模式</strong>:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 反模式 1:default ServiceAccount 直接绑 cluster-admin</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># (省事,但任何 Pod 都成了 root)</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">kind</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ClusterRoleBinding</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">subjects</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">kind</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ServiceAccount</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">default</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    namespace</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">default</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">roleRef</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">cluster-admin</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 反模式 2:Role 里写 verbs: [&quot;*&quot;]</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># (运维图省事,实际等于 admin)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 反模式 3:给 Pod 挂的 ServiceAccount 有 list secrets 权限</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># → 攻击者拿到 token 就能读所有 Secret</span></span></code></pre></div><p><strong>等价的提权链</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>有 create pods 权限</span></span>
<span class="line"><span>   → 我自己创建一个 hostPath: / 挂载的 Pod</span></span>
<span class="line"><span>   → exec 进去 → chroot /host → 拿到 Node 上 root</span></span>
<span class="line"><span></span></span>
<span class="line"><span>有 exec into kube-system pods 的权限</span></span>
<span class="line"><span>   → kubectl exec -n kube-system kube-controller-manager-xxx cat /etc/kubernetes/admin.conf</span></span>
<span class="line"><span>   → 拿到 cluster-admin 凭证</span></span>
<span class="line"><span></span></span>
<span class="line"><span>有 create/update validating-webhook-configurations 权限</span></span>
<span class="line"><span>   → 注册一个恶意 webhook 拦截所有 API 调用</span></span>
<span class="line"><span>   → 静默泄露所有 Secret</span></span></code></pre></div><p><strong>RBAC 审计的核心问题不是&quot;谁有 admin&quot;,是&quot;谁能通过组合权限走到 admin&quot;</strong>。工具:<code>kubectl-who-can</code>、<code>rbac-lookup</code>、<code>kube-hunter</code>。</p><h3 id="_4-3-etcd-没认证-全部-secret-裸奔" tabindex="-1">4.3 etcd 没认证 = 全部 Secret 裸奔 <a class="header-anchor" href="#_4-3-etcd-没认证-全部-secret-裸奔" aria-label="Permalink to &quot;4.3 etcd 没认证 = 全部 Secret 裸奔&quot;">​</a></h3><p>K8s 把<strong>所有状态</strong>存在 etcd——包括 ConfigMap、Secret、ServiceAccount Token、TLS 证书私钥。错配的 etcd(监听 0.0.0.0:2379、没 mTLS、没认证)= 任何能访问 2379 的人,直接读所有 Secret。Shodan 上常年有几千个开放的 etcd。</p><p><strong>Tesla 2018 那次挖矿事故</strong>,根因就是 Kubernetes Dashboard 没鉴权 + 暴露公网,攻击者从 dashboard 拿到 AWS IAM 凭证——一条龙服务。<strong>etcd 应该</strong>:只监听 control plane 内网、启用 client-cert mTLS、数据落盘<strong>加密</strong>(<code>--encryption-provider-config</code>,用 KMS 做密钥)。</p><h3 id="_4-4-serviceaccount-token-的滥用" tabindex="-1">4.4 ServiceAccount Token 的滥用 <a class="header-anchor" href="#_4-4-serviceaccount-token-的滥用" aria-label="Permalink to &quot;4.4 ServiceAccount Token 的滥用&quot;">​</a></h3><p>每个 Pod 默认自动挂载所在 namespace 的 default ServiceAccount Token 到 <code>/var/run/secrets/kubernetes.io/serviceaccount/token</code>。<strong>这个 token 在 K8s 1.21 之前是永久有效的</strong>——撤销靠重建 ServiceAccount。</p><p><strong>现代做法</strong>:K8s 1.22+ 默认 <strong>BoundServiceAccountToken</strong>(有过期时间、绑定 Pod、audience-bound);不需要访问 API 的 Pod 设 <code>automountServiceAccountToken: false</code>;每个微服务用<strong>专门的 ServiceAccount</strong>,绑定最小权限 Role;监控异常 API 调用(audit log)。</p><h3 id="_4-5-pod-安全标准-pss-psp-的替代" tabindex="-1">4.5 Pod 安全标准(PSS):PSP 的替代 <a class="header-anchor" href="#_4-5-pod-安全标准-pss-psp-的替代" aria-label="Permalink to &quot;4.5 Pod 安全标准(PSS):PSP 的替代&quot;">​</a></h3><p>K8s 1.25 起,旧的 PodSecurityPolicy(PSP)正式移除,<strong>替代方案是 Pod Security Standards</strong>——三个预设级别:</p><table tabindex="0"><thead><tr><th>级别</th><th>含义</th><th>适用</th></tr></thead><tbody><tr><td><code>privileged</code></td><td>不限制(最危险)</td><td>系统组件、特殊场景</td></tr><tr><td><code>baseline</code></td><td>防最明显的提权</td><td>一般业务</td></tr><tr><td><code>restricted</code></td><td>严格遵守 hardening</td><td>生产业务的默认</td></tr></tbody></table><p><code>restricted</code> 级别强制:</p><ul><li><code>runAsNonRoot: true</code></li><li>不允许 <code>privileged</code> / <code>hostNetwork</code> / <code>hostPID</code> / <code>hostPath</code></li><li>必须 drop <code>ALL</code> capabilities,只能 add 极少几个</li><li>seccomp = <code>RuntimeDefault</code></li><li>只允许特定的 volume 类型</li></ul><p><strong>namespace 级别开关</strong>:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">apiVersion</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">v1</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">kind</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Namespace</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">metadata</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">prod</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  labels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    pod-security.kubernetes.io/enforce</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">restricted</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    pod-security.kubernetes.io/audit</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">restricted</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    pod-security.kubernetes.io/warn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">restricted</span></span></code></pre></div><p>—— 这是 K8s 给的&quot;开箱即用&quot;的纸糊门加强版。生产 namespace 默认 <code>restricted</code>,例外再单独申请。</p><hr><h2 id="五、云上-iam-secret-真实事故" tabindex="-1">五、云上 IAM / Secret / 真实事故 <a class="header-anchor" href="#五、云上-iam-secret-真实事故" aria-label="Permalink to &quot;五、云上 IAM / Secret / 真实事故&quot;">​</a></h2><h3 id="_5-1-iam-错配-云上事故的头号杀手" tabindex="-1">5.1 IAM 错配:云上事故的头号杀手 <a class="header-anchor" href="#_5-1-iam-错配-云上事故的头号杀手" aria-label="Permalink to &quot;5.1 IAM 错配:云上事故的头号杀手&quot;">​</a></h3><p><strong>Capital One 2019</strong> —— 1 亿用户数据泄露,公司被罚 $1.9 亿。攻击链:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. WAF 服务器有 SSRF 漏洞</span></span>
<span class="line"><span>2. SSRF 访问 169.254.169.254(EC2 metadata 服务)</span></span>
<span class="line"><span>   → 拿到附加在 EC2 上的 IAM Role 临时凭证</span></span>
<span class="line"><span>3. 这个 Role 有 ListBuckets / GetObject 权限(过宽)</span></span>
<span class="line"><span>4. 列出所有 S3 bucket,拖走 1 亿条数据</span></span></code></pre></div><p><strong>根因不是 SSRF,是 IAM Role 给了&quot;宽到能扫整个 S3&quot;的权限</strong>。云原生时代的 IAM 错配,严重程度等同于&quot;把数据库账号写到前端代码里&quot;。</p><h3 id="_5-2-iam-反模式" tabindex="-1">5.2 IAM 反模式 <a class="header-anchor" href="#_5-2-iam-反模式" aria-label="Permalink to &quot;5.2 IAM 反模式&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>❌ root account 跑日常任务         → 泄露 = 整个账号</span></span>
<span class="line"><span>❌ Role 加 AdministratorAccess     → 横向移动毫无阻力</span></span>
<span class="line"><span>❌ 跨账号信任 Principal: &quot;*&quot;        → 全世界 AWS 账号能 assume</span></span>
<span class="line"><span>❌ S3 bucket 默认公开              → 历史上无数事故的源头</span></span>
<span class="line"><span>❌ access key 写进代码 / 镜像 / 公开 GitHub</span></span>
<span class="line"><span>   → GitHub 上 bot 24/7 扫,几分钟就被滥用挖矿</span></span></code></pre></div><h3 id="_5-3-iam-正确姿势" tabindex="-1">5.3 IAM 正确姿势 <a class="header-anchor" href="#_5-3-iam-正确姿势" aria-label="Permalink to &quot;5.3 IAM 正确姿势&quot;">​</a></h3><ul><li>最小权限:Action 精确,资源精确到 ARN</li><li>用 <strong>IRSA / Workload Identity</strong>:Pod 直接 assume 云 Role,不再用 metadata 凭证</li><li>跨账号信任:Principal 限定账号 + ExternalId</li><li>永久 access key 一律不用,改用 STS 临时凭证</li><li>CloudTrail / Audit Log 开全,异常 API 调用告警</li><li>AWS Access Analyzer / GCP IAM Recommender 定期跑</li><li><strong>EC2 metadata 强制 IMDSv2</strong>——需要 PUT 拿 token,大多数 SSRF 默认不发 PUT 直接堵死。这是 Capital One 之后的直接补救。</li></ul><h3 id="_5-4-secret-管理-k8s-secret-不是加密的" tabindex="-1">5.4 Secret 管理:K8s Secret 不是加密的 <a class="header-anchor" href="#_5-4-secret-管理-k8s-secret-不是加密的" aria-label="Permalink to &quot;5.4 Secret 管理:K8s Secret 不是加密的&quot;">​</a></h3><p><strong>最大的误区</strong>:<code>kubectl create secret</code> 出来的东西看着是 base64 编码,<strong>很多人以为&quot;这就是加密&quot;</strong>。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;super-secret-password&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> base64</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># c3VwZXItc2VjcmV0LXBhc3N3b3Jk</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 再 decode 回来:</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;c3VwZXItc2VjcmV0LXBhc3N3b3Jk&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> base64</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># super-secret-password</span></span></code></pre></div><p><strong>base64 是编码不是加密</strong>。K8s Secret 的真正&quot;安全性&quot;在于:</p><ol><li>RBAC 控制谁能 <code>get</code> Secret(默认值给的常常太宽)</li><li>etcd encryption-at-rest(默认<strong>不开</strong>,要手动配置)</li><li>不进 git,不打到日志</li></ol><h3 id="_5-5-现代-secret-方案对比" tabindex="-1">5.5 现代 Secret 方案对比 <a class="header-anchor" href="#_5-5-现代-secret-方案对比" aria-label="Permalink to &quot;5.5 现代 Secret 方案对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方案</th><th>心智模型</th><th>优点</th><th>缺点</th></tr></thead><tbody><tr><td><strong>K8s 原生 Secret</strong></td><td>etcd 里的 base64</td><td>简单原生</td><td>默认未加密 / RBAC 易配错</td></tr><tr><td><strong>etcd KMS encryption</strong></td><td>API Server 写入前先用 KMS 加密</td><td>静态数据加密</td><td>不阻止有 API 权限的人读</td></tr><tr><td><strong>HashiCorp Vault</strong></td><td>集中式秘密管理 / 动态凭证</td><td>短期凭证 / 审计完善</td><td>自建运维成本</td></tr><tr><td><strong>Cloud KMS / Secrets Manager</strong></td><td>云厂商管理(AWS SM / GCP Secret Manager)</td><td>托管 / IAM 集成</td><td>锁厂商</td></tr><tr><td><strong>Sealed Secrets</strong>(Bitnami)</td><td>公钥加密的 Secret 可入 git</td><td>GitOps 友好</td><td>解密在集群侧</td></tr><tr><td><strong>SOPS</strong>(Mozilla)</td><td>用 KMS/PGP 加密 YAML 字段</td><td>文件级粒度 / git 友好</td><td>需配套工作流</td></tr><tr><td><strong>External Secrets Operator</strong></td><td>把外部 Secret 同步到 K8s Secret</td><td>统一抽象多个 backend</td><td>仍然落到 etcd Secret</td></tr></tbody></table><p><strong>实践推荐</strong>(按规模递进):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>小团队 / 单集群:</span></span>
<span class="line"><span>  K8s Secret + etcd encryption-at-rest + 严格 RBAC</span></span>
<span class="line"><span></span></span>
<span class="line"><span>中等规模 / 多环境:</span></span>
<span class="line"><span>  Sealed Secrets 或 SOPS,Secret 可放 git</span></span>
<span class="line"><span></span></span>
<span class="line"><span>大规模 / 多云 / 强审计:</span></span>
<span class="line"><span>  Vault + 短期动态凭证(数据库 / 云 API 都现申请)</span></span>
<span class="line"><span>  或 cloud-native(AWS Secrets Manager + IRSA)</span></span></code></pre></div><p>**&quot;短期凭证 &gt; 长期凭证&quot;**是云原生 Secret 的核心进步——Vault 可以给应用一个 5 分钟的数据库账号,过期作废。即使泄露,攻击窗口极短。</p><h3 id="_5-6-三个标杆事故" tabindex="-1">5.6 三个标杆事故 <a class="header-anchor" href="#_5-6-三个标杆事故" aria-label="Permalink to &quot;5.6 三个标杆事故&quot;">​</a></h3><p><strong>Tesla K8s 挖矿(2018)</strong>:Tesla 跑在 AWS,Kubernetes Dashboard 没鉴权直挂公网 → 攻击者 exec 进 Pod → Pod 里挂的 ServiceAccount + Pod 元数据有 AWS 凭证 → 一边给 Pod 装挖矿一边开 EC2 挖矿,用 CloudFlare 做 C2 流量伪装,延迟 1 年才被发现。<strong>核心教训</strong>:Dashboard 默认上线就是错,ServiceAccount Token 自动挂载就是错,云凭证下沉到 Pod 元数据就是错。</p><p><strong>Capital One(2019)</strong>:见 5.1。<strong>核心教训</strong>:IAM Role 必须最小权限 + 强制 IMDSv2 + SSRF 防御。</p><p><strong>Codecov(2021)</strong>:Codecov 的 bash uploader 脚本被改了一行(攻击者拿到 Docker 镜像构建凭证),这行代码 exfil 了 CI 环境变量到攻击者服务器——大量公司的 CI 环境变量里有云凭证 / GitHub token / npm token。攻击者用这些凭证横向渗透了 HashiCorp / Twilio / Rapid7 等公司。<strong>核心教训</strong>:<strong>CI 环境变量 = Secret 的&quot;宿舍楼&quot;</strong>;供应链下游一个工具的 RCE = 上游所有客户的 RCE(见 26 篇供应链)。</p><hr><h2 id="六、k8s-上线前安全-checklist" tabindex="-1">六、K8s 上线前安全 checklist <a class="header-anchor" href="#六、k8s-上线前安全-checklist" aria-label="Permalink to &quot;六、K8s 上线前安全 checklist&quot;">​</a></h2><p>把这份贴到 PR 模板里,生产环境上线必过:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>═══ 集群层 ═══</span></span>
<span class="line"><span>[ ] API Server 不直接对公网开放(或前置 IAM 网关)</span></span>
<span class="line"><span>[ ] --anonymous-auth=false / --authorization-mode=RBAC,Node</span></span>
<span class="line"><span>[ ] kubelet 只监听内网 / 关闭只读端口 10255</span></span>
<span class="line"><span>[ ] etcd 开启 mTLS + encryption-at-rest(KMS 做密钥)</span></span>
<span class="line"><span>[ ] audit log 开启,转发到 SIEM</span></span>
<span class="line"><span>[ ] Control plane 用托管服务(EKS/GKE/AKS)优先</span></span>
<span class="line"><span></span></span>
<span class="line"><span>═══ Pod / 镜像层 ═══</span></span>
<span class="line"><span>[ ] 生产 namespace 默认 Pod Security: restricted</span></span>
<span class="line"><span>[ ] runAsNonRoot=true,readOnlyRootFilesystem=true</span></span>
<span class="line"><span>[ ] drop ALL capabilities,seccompProfile=RuntimeDefault</span></span>
<span class="line"><span>[ ] 不挂 hostPath / hostNetwork / hostPID(系统组件除外)</span></span>
<span class="line"><span>[ ] 镜像 pin 到 digest,不用 :latest</span></span>
<span class="line"><span>[ ] 可信 registry + Cosign 签名校验</span></span>
<span class="line"><span>[ ] CI 跑漏洞扫描(Trivy / Grype),阻断高危</span></span>
<span class="line"><span>[ ] base image 用 distroless / alpine 无 shell</span></span>
<span class="line"><span></span></span>
<span class="line"><span>═══ RBAC / ServiceAccount 层 ═══</span></span>
<span class="line"><span>[ ] 每个工作负载独立 SA,不用 default</span></span>
<span class="line"><span>[ ] automountServiceAccountToken=false(不需要 API 时)</span></span>
<span class="line"><span>[ ] BoundServiceAccountToken(token 有 audience + 过期)</span></span>
<span class="line"><span>[ ] 任何 SA 都不绑 cluster-admin(除短期 break-glass)</span></span>
<span class="line"><span>[ ] 定期跑 kubectl-who-can / rbac-lookup 审计</span></span>
<span class="line"><span>[ ] webhook configuration create/update 严格控制</span></span>
<span class="line"><span></span></span>
<span class="line"><span>═══ Secret 层 ═══</span></span>
<span class="line"><span>[ ] K8s Secret 不进 git(Sealed Secrets / SOPS / Vault)</span></span>
<span class="line"><span>[ ] etcd encryption-at-rest 开启</span></span>
<span class="line"><span>[ ] 长期凭证用动态短期凭证替代</span></span>
<span class="line"><span>[ ] 不在镜像 / ConfigMap / env 里硬编码 Secret</span></span>
<span class="line"><span></span></span>
<span class="line"><span>═══ 云 IAM 层 ═══</span></span>
<span class="line"><span>[ ] 节点 IAM Role 最小权限,不含 *</span></span>
<span class="line"><span>[ ] 用 IRSA / Workload Identity 替代节点级凭证</span></span>
<span class="line"><span>[ ] EC2 metadata 强制 IMDSv2</span></span>
<span class="line"><span>[ ] CloudTrail / Cloud Audit Log 全开</span></span>
<span class="line"><span>[ ] S3 bucket 默认 Block Public Access</span></span>
<span class="line"><span>[ ] 跨账号信任带 ExternalId,Principal 不为 *</span></span>
<span class="line"><span>[ ] 不用 root account 做日常操作</span></span>
<span class="line"><span></span></span>
<span class="line"><span>═══ 网络 / 运行时 ═══</span></span>
<span class="line"><span>[ ] NetworkPolicy 默认拒绝,按需放行(零信任)</span></span>
<span class="line"><span>[ ] Service Mesh mTLS(Istio / Linkerd)</span></span>
<span class="line"><span>[ ] Ingress 强制 TLS,弱 cipher 禁用</span></span>
<span class="line"><span>[ ] 跑 Falco / Tetragon 运行时检测</span></span>
<span class="line"><span>[ ] 跑 kube-bench(CIS Benchmark)/ kube-hunter</span></span>
<span class="line"><span>[ ] 定期演练:模拟容器逃逸,验证能否发现</span></span></code></pre></div><blockquote><p>这份 checklist 看着多,<strong>实际是云原生时代&quot;代替防火墙规则&quot;的等价物</strong>——以前一台机器一道墙,现在每个 Pod 一道纸糊门,纸糊门多但每张都得检查。</p></blockquote><hr><h2 id="七、踩坑提醒-收敛" tabindex="-1">七、踩坑提醒(收敛) <a class="header-anchor" href="#七、踩坑提醒-收敛" aria-label="Permalink to &quot;七、踩坑提醒(收敛)&quot;">​</a></h2><ol><li><strong>以为容器是虚拟机</strong>——共享内核,逃逸是配置问题不是 0day 问题</li><li><strong><code>--privileged</code> 当默认开</strong>——等于给容器宿主 root</li><li><strong>挂 <code>docker.sock</code> 当无害</strong>——等于宿主 root</li><li><strong>镜像用 <code>:latest</code></strong>——下次 build 就可能拿到攻击者的版本</li><li><strong>K8s Secret 当加密</strong>——base64 是编码不是加密</li><li><strong>default ServiceAccount 默认挂</strong>——业务 Pod 自动有 API 调用能力</li><li><strong>IAM Role 写 <code>*:*</code></strong>——SSRF 一发,整个账号陷落</li><li><strong>etcd 不开 mTLS / 加密</strong>——拿到 etcd = 拿到所有 Secret</li><li><strong>kubelet 暴露 10250</strong>——等价于把 kubectl exec 开给互联网</li><li><strong>CI 环境变量塞所有凭证</strong>——Codecov 那种供应链事故的标准入口</li></ol><hr><h2 id="八、本篇与全系列的位置" tabindex="-1">八、本篇与全系列的位置 <a class="header-anchor" href="#八、本篇与全系列的位置" aria-label="Permalink to &quot;八、本篇与全系列的位置&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>26 供应链(npm / SBOM / Sigstore)</span></span>
<span class="line"><span>27 SDL(开发流程内嵌的安全)</span></span>
<span class="line"><span>28 容器与云安全 ← 你在这里</span></span>
<span class="line"><span>29 监控与应急响应(看到攻击 / 响应攻击 / 复盘)</span></span>
<span class="line"><span>30 AI 安全(LLM / Agent 时代的新攻击面)</span></span></code></pre></div><p>容器和云的安全本质上是<strong>配置安全</strong>——代码可能没漏洞,但 YAML 一行配错,整个云账号陷落。SDL(27 篇)的角度看,<strong>云安全的最大杠杆是&quot;把所有配置变成代码,把代码变成 PR,把 PR 变成审计入口&quot;</strong>——这就是为什么 Terraform / Pulumi 加 OPA / Checkov 这套&quot;IaC + 策略即代码&quot;成为云原生时代的安全主战场。</p><p>下一篇:<code>29-监控与应急响应.md</code>,讲清楚 IDS / SIEM / EDR 的工程视角、为什么&quot;日志开了不看等于没开&quot;、Splunk / Elastic / Loki 在 SOC 里的真实分工、一次 incident response 的标准节奏(detect → contain → eradicate → recover → lessons learned),以及为什么&quot;事后复盘&quot;才是安全工程的真核——每一次事故都是一次免费的红队演练,看不懂等于白被打了一次。</p>`,119)])])}const u=a(i,[["render",p]]);export{k as __pageData,u as default};
